from sympy import bernoulli
def A345037(n):
    c, j = 0, 1
    while j <= n:
        k = n//j
        m = n//k
        c += (1 if k&1 else -1)*(bernoulli(k,m+1)-bernoulli(k,j))//k
        j = m+1
    return c # _Chai Wah Wu_, May 14 2026

